"use client"

import {
  useEffect,
  useState,
} from "react"

import { useRouter } from "next/navigation"

import { useAuth } from "@/contexts/AuthContext"

import {
  hasAppAccess,
} from "@/lib/subscription"

import {
  SubscriptionExpired,
} from "@/components/screens/subscription-expired"

export function ProtectedRoute({
  children,
}: {
  children: React.ReactNode
}) {
  const { user, loading } =
    useAuth()

  const router =
    useRouter()

  const [
    checkingAccess,
    setCheckingAccess,
  ] = useState(true)

  const [
    accessAllowed,
    setAccessAllowed,
  ] = useState(false)

  useEffect(() => {
    const checkAccess =
      async () => {
        try {
          if (
            !loading &&
            !user
          ) {
            router.push(
              "/onboarding"
            )

            return
          }

          if (!user) {
            return
          }

          const allowed =
            await hasAppAccess()

          setAccessAllowed(
            allowed
          )

        } catch (error) {
          console.error(
            error
          )

          setAccessAllowed(
            false
          )

        } finally {
          setCheckingAccess(
            false
          )
        }
      }

    checkAccess()
  }, [
    user,
    loading,
    router,
  ])

  // AUTH LOADING

  if (loading) {
    return (
      <div className="h-screen flex items-center justify-center text-sm text-gray-500">
        Loading AquaOps...
      </div>
    )
  }

  // NO USER

  if (!user) {
    return null
  }

  // ACCESS CHECK

  if (
    checkingAccess
  ) {
    return (
      <div className="h-screen flex items-center justify-center text-sm text-gray-500">
        Checking subscription...
      </div>
    )
  }

  // SUBSCRIPTION EXPIRED

  if (
    !accessAllowed
  ) {
    return (
      <SubscriptionExpired />
    )
  }

  // AUTHORIZED

  return <>{children}</>
}